const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, WidthType, BorderStyle, PageBreak, Footer, PageNumber,
  ShadingType, VerticalAlign, TableLayoutType } = require('docx');
const fs = require('fs');

// ===================== GOST STANDARD FORMATTING =====================
const F = "Times New Roman";
const SZ = 28;        // 14pt
const SZ_TITLE = 32;  // 16pt for main titles
const SZ_SM = 24;     // 12pt for small text

// Page margins: left 3cm, right 1.5cm, top 2cm, bottom 2cm
const ML = 1701; // 3cm
const MR = 851;  // 1.5cm
const MT = 1134; // 2cm
const MB = 1134; // 2cm
const PW = 11906; // A4 width
const PH = 16838; // A4 height
const CW = PW - ML - MR; // content width = 9354

const thinBorder = { style: BorderStyle.SINGLE, size: 1, color: "000000" };
const borders = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };
const noBorder = { style: BorderStyle.NONE, size: 0 };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

// Standard paragraph: 14pt TNR, justified, first line indent 1.25cm, single spacing, 0pt before/after
const p = (text, opts = {}) => new Paragraph({
  spacing: { after: 0, before: 0, line: 240 },
  alignment: opts.align || AlignmentType.JUSTIFIED,
  indent: opts.noIndent ? undefined : { firstLine: 709 },
  children: Array.isArray(text) ? text : [
    new TextRun({ text, font: F, size: opts.size || SZ, bold: opts.bold || false, italics: opts.italic || false })
  ]
});

// Heading paragraph: bold, centered, no indent
const h1 = (text) => new Paragraph({
  spacing: { before: 240, after: 120, line: 240 },
  alignment: AlignmentType.CENTER,
  children: [new TextRun({ text: text.toUpperCase(), font: F, size: SZ, bold: true })]
});

const h2 = (text) => new Paragraph({
  spacing: { before: 240, after: 120, line: 240 },
  alignment: AlignmentType.LEFT,
  indent: { firstLine: 709 },
  children: [new TextRun({ text, font: F, size: SZ, bold: true })]
});

// Empty line
const br = () => new Paragraph({ spacing: { after: 0, before: 0, line: 240 }, children: [] });

// Page break
const pageBreak = () => new Paragraph({
  children: [new TextRun({ children: [new PageBreak()] })]
});

// Bold + normal text in one paragraph
const pMixed = (parts) => new Paragraph({
  spacing: { after: 0, before: 0, line: 240 },
  alignment: AlignmentType.JUSTIFIED,
  indent: { firstLine: 709 },
  children: parts.map(([text, bold, italic]) =>
    new TextRun({ text, font: F, size: SZ, bold: !!bold, italics: !!italic })
  )
});

// Numbered formula claim
const claim = (num, text) => new Paragraph({
  spacing: { after: 0, before: 120, line: 240 },
  alignment: AlignmentType.JUSTIFIED,
  indent: { firstLine: 709 },
  children: [
    new TextRun({ text: `${num}. `, font: F, size: SZ, bold: true }),
    new TextRun({ text, font: F, size: SZ })
  ]
});

// Table cell helper
const tc = (content, opts = {}) => new TableCell({
  borders: opts.noBorders ? noBorders : borders,
  width: opts.w ? { size: opts.w, type: WidthType.DXA } : undefined,
  columnSpan: opts.cs || 1,
  rowSpan: opts.rs || 1,
  verticalAlign: opts.va || VerticalAlign.CENTER,
  shading: opts.fill ? { fill: opts.fill, type: ShadingType.CLEAR } : undefined,
  margins: { top: 40, bottom: 40, left: 80, right: 80 },
  children: Array.isArray(content) ? content : [
    new Paragraph({
      spacing: { after: 0, before: 0, line: 240 },
      alignment: opts.align || AlignmentType.CENTER,
      children: [new TextRun({ text: content, font: F, size: opts.sz || SZ, bold: opts.bold || false })]
    })
  ]
});

// Convert long text block to array of paragraphs (split by double newline)
const textToParas = (text) => text.split('\n\n').filter(t => t.trim()).map(t => p(t.trim()));

